package com.copperhill.backoffice;

import java.io.*;
import java.sql.*;

public class BackofficeReviewQuery {
    private static final String DB_URL = "jdbc:mysql://localhost:3306/appdb";
    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "apppass";

    public String run(String inputPath) throws Exception {
        String input = "";
        try (BufferedReader br = new BufferedReader(new FileReader(inputPath))) {
            String line = br.readLine();
            input = (line == null) ? "" : line;
        }

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            String sql = "INSERT INTO reviews(reviewer, result) VALUES ('" + input + "', 'import')";
            try (Statement st = conn.createStatement()) {
                st.addBatch(sql);
                int[] results = st.executeBatch();
                return "batch=" + results.length;
            }
        }
    }
}

